window.BIBLE["Ephesians"] = {"1":{"chapter":"1","title":"BLESSED WITH EVERY SPIRITUAL BLESSING","verses":{"1":{"text":"Paul, an apostle of Jesus Christ by the will of God, to the saints which are at Ephesus, and to the faithful in Christ Jesus:","ref":"Ephesians 1:1","synthesized":"Paul, an apostle of Christ Jesus by the will of God,  To the saints in Ephesus, the faithful in Christ Jesus:","sources":{"KJV":{"text":"Paul, an apostle of Jesus Christ by the will of God, to the saints which are at Ephesus, and to the faithful in Christ Jesus:"},"BSB":{"text":"Paul, an apostle of Christ Jesus by the will of God,  To the saints in Ephesus, the faithful in Christ Jesus:"}},"definableWords":["apostle","Christ","God"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"Grace be to you, and peace, from God our Father, and from the Lord Jesus Christ.","ref":"Ephesians 1:2","synthesized":"Grace and peace to you from God our Father and the Lord Jesus Christ.","sources":{"KJV":{"text":"Grace be to you, and peace, from God our Father, and from the Lord Jesus Christ."},"BSB":{"text":"Grace and peace to you from God our Father and the Lord Jesus Christ."}},"definableWords":["grace","peace","God","Father","Lord","Christ"],"peopleInVerse":["Jesus"]},"3":{"text":"Blessed be the God and Father of our Lord Jesus Christ, who hath blessed us with all spiritual blessings in heavenly places in Christ:","ref":"Ephesians 1:3","synthesized":"Blessed be the God and Father of our Lord Jesus Christ, who has blessed us in Christ with every spiritual blessing in the heavenly realms.","sources":{"KJV":{"text":"Blessed be the God and Father of our Lord Jesus Christ, who hath blessed us with all spiritual blessings in heavenly places in Christ:"},"BSB":{"text":"Blessed be the God and Father of our Lord Jesus Christ, who has blessed us in Christ with every spiritual blessing in the heavenly realms."}},"definableWords":["blessed","God","Father","Lord","Christ","blessing"],"peopleInVerse":["Jesus"]},"4":{"text":"According as he hath chosen us in him before the foundation of the world, that we should be holy and without blame before him in love:","ref":"Ephesians 1:4","synthesized":"For He chose us in Him before the foundation of the world to be holy and blameless in His presence. In love","sources":{"KJV":{"text":"According as he hath chosen us in him before the foundation of the world, that we should be holy and without blame before him in love:"},"BSB":{"text":"For He chose us in Him before the foundation of the world to be holy and blameless in His presence. In love"}},"definableWords":["holy","love"],"peopleInVerse":[]},"5":{"text":"Having predestinated us unto the adoption of children by Jesus Christ to himself, according to the good pleasure of his will,","ref":"Ephesians 1:5","synthesized":"He predestined us for adoption as His sons through Jesus Christ, according to the good pleasure of His will,","sources":{"KJV":{"text":"Having predestinated us unto the adoption of children by Jesus Christ to himself, according to the good pleasure of his will,"},"BSB":{"text":"He predestined us for adoption as His sons through Jesus Christ, according to the good pleasure of His will,"}},"definableWords":["sons","Christ","good"],"peopleInVerse":["Jesus"]},"6":{"text":"To the praise of the glory of his grace, wherein he hath made us accepted in the beloved.","ref":"Ephesians 1:6","synthesized":"to the praise of His glorious grace, which He has freely given us in the Beloved One.","sources":{"KJV":{"text":"To the praise of the glory of his grace, wherein he hath made us accepted in the beloved."},"BSB":{"text":"to the praise of His glorious grace, which He has freely given us in the Beloved One."}},"definableWords":["praise","grace","one"],"peopleInVerse":[]},"7":{"text":"In whom we have redemption through his blood, the forgiveness of sins, according to the riches of his grace;","ref":"Ephesians 1:7","synthesized":"In Him we have redemption through His blood, the forgiveness of our trespasses, according to the riches of His grace","sources":{"KJV":{"text":"In whom we have redemption through his blood, the forgiveness of sins, according to the riches of his grace;"},"BSB":{"text":"In Him we have redemption through His blood, the forgiveness of our trespasses, according to the riches of His grace"}},"definableWords":["redemption","blood","grace"],"peopleInVerse":[]},"8":{"text":"Wherein he hath abounded toward us in all wisdom and prudence;","ref":"Ephesians 1:8","synthesized":"that He lavished on us with all wisdom and understanding.","sources":{"KJV":{"text":"Wherein he hath abounded toward us in all wisdom and prudence;"},"BSB":{"text":"that He lavished on us with all wisdom and understanding."}},"definableWords":["wisdom"],"peopleInVerse":[]},"9":{"text":"Having made known unto us the mystery of his will, according to his good pleasure which he hath purposed in himself:","ref":"Ephesians 1:9","synthesized":"And He has made known to us the mystery of His will according to His good pleasure, which He purposed in Christ","sources":{"KJV":{"text":"Having made known unto us the mystery of his will, according to his good pleasure which he hath purposed in himself:"},"BSB":{"text":"And He has made known to us the mystery of His will according to His good pleasure, which He purposed in Christ"}},"definableWords":["made","good","Christ"],"peopleInVerse":[]},"10":{"text":"That in the dispensation of the fulness of times he might gather together in one all things in Christ, both which are in heaven, and which are on earth; even in him:","ref":"Ephesians 1:10","synthesized":"as a plan for the fullness of time, to bring all things in heaven and on earth together in Christ.","sources":{"KJV":{"text":"That in the dispensation of the fulness of times he might gather together in one all things in Christ, both which are in heaven, and which are on earth; even in him:"},"BSB":{"text":"as a plan for the fullness of time, to bring all things in heaven and on earth together in Christ."}},"definableWords":["heaven","earth","Christ"],"peopleInVerse":[]},"11":{"text":"In whom also we have obtained an inheritance, being predestinated according to the purpose of him who worketh all things after the counsel of his own will:","ref":"Ephesians 1:11","synthesized":"In Him we were also chosen as God’s own, having been predestined according to the plan of Him who works out everything by the counsel of His will,","sources":{"KJV":{"text":"In whom also we have obtained an inheritance, being predestinated according to the purpose of him who worketh all things after the counsel of his own will:"},"BSB":{"text":"In Him we were also chosen as God’s own, having been predestined according to the plan of Him who works out everything by the counsel of His will,"}},"definableWords":["God","works"],"peopleInVerse":[]},"12":{"text":"That we should be to the praise of his glory, who first trusted in Christ.","ref":"Ephesians 1:12","synthesized":"in order that we, who were the first to hope in Christ, would be for the praise of His glory.","sources":{"KJV":{"text":"That we should be to the praise of his glory, who first trusted in Christ."},"BSB":{"text":"in order that we, who were the first to hope in Christ, would be for the praise of His glory."}},"definableWords":["hope","Christ","praise","glory"],"peopleInVerse":[]},"13":{"text":"In whom ye also trusted, after that ye heard the word of truth, the gospel of your salvation: in whom also after that ye believed, ye were sealed with that holy Spirit of promise,","ref":"Ephesians 1:13","synthesized":"And in Him, having heard and believed the word of truth—the gospel of your salvation—you were sealed with the promised Holy Spirit,","sources":{"KJV":{"text":"In whom ye also trusted, after that ye heard the word of truth, the gospel of your salvation: in whom also after that ye believed, ye were sealed with that holy Spirit of promise,"},"BSB":{"text":"And in Him, having heard and believed the word of truth—the gospel of your salvation—you were sealed with the promised Holy Spirit,"}},"definableWords":["believed","word","truth","gospel","salvation","holy","Spirit"],"peopleInVerse":[]},"14":{"text":"Which is the earnest of our inheritance until the redemption of the purchased possession, unto the praise of his glory.","ref":"Ephesians 1:14","synthesized":"who is the pledge of our inheritance until the redemption of those who are God’s possession, to the praise of His glory.","sources":{"KJV":{"text":"Which is the earnest of our inheritance until the redemption of the purchased possession, unto the praise of his glory."},"BSB":{"text":"who is the pledge of our inheritance until the redemption of those who are God’s possession, to the praise of His glory."}},"definableWords":["redemption","God","praise","glory"],"peopleInVerse":[]},"15":{"text":"Wherefore I also, after I heard of your faith in the Lord Jesus, and love unto all the saints,","ref":"Ephesians 1:15","synthesized":"For this reason, ever since I heard about your faith in the Lord Jesus and your love for all the saints,","sources":{"KJV":{"text":"Wherefore I also, after I heard of your faith in the Lord Jesus, and love unto all the saints,"},"BSB":{"text":"For this reason, ever since I heard about your faith in the Lord Jesus and your love for all the saints,"}},"definableWords":["faith","Lord","love"],"peopleInVerse":["Jesus"]},"16":{"text":"Cease not to give thanks for you, making mention of you in my prayers;","ref":"Ephesians 1:16","synthesized":"I have not stopped giving thanks for you, remembering you in my prayers,","sources":{"KJV":{"text":"Cease not to give thanks for you, making mention of you in my prayers;"},"BSB":{"text":"I have not stopped giving thanks for you, remembering you in my prayers,"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"That the God of our Lord Jesus Christ, the Father of glory, may give unto you the spirit of wisdom and revelation in the knowledge of him:","ref":"Ephesians 1:17","synthesized":"that the God of our Lord Jesus Christ, the glorious Father, may give you a spirit of wisdom and revelation in your knowledge of Him.","sources":{"KJV":{"text":"That the God of our Lord Jesus Christ, the Father of glory, may give unto you the spirit of wisdom and revelation in the knowledge of him:"},"BSB":{"text":"that the God of our Lord Jesus Christ, the glorious Father, may give you a spirit of wisdom and revelation in your knowledge of Him."}},"definableWords":["God","Lord","Christ","Father","spirit","wisdom","knowledge"],"peopleInVerse":["Jesus"]},"18":{"text":"The eyes of your understanding being enlightened; that ye may know what is the hope of his calling, and what the riches of the glory of his inheritance in the saints,","ref":"Ephesians 1:18","synthesized":"I ask that the eyes of your heart may be enlightened, so that you may know the hope of His calling, the riches of His glorious inheritance in the saints,","sources":{"KJV":{"text":"The eyes of your understanding being enlightened; that ye may know what is the hope of his calling, and what the riches of the glory of his inheritance in the saints,"},"BSB":{"text":"I ask that the eyes of your heart may be enlightened, so that you may know the hope of His calling, the riches of His glorious inheritance in the saints,"}},"definableWords":["heart","hope"],"peopleInVerse":[]},"19":{"text":"And what is the exceeding greatness of his power to us-ward who believe, according to the working of his mighty power,","ref":"Ephesians 1:19","synthesized":"and the surpassing greatness of His power to us who believe. These are in accordance with the working of His mighty strength,","sources":{"KJV":{"text":"And what is the exceeding greatness of his power to us-ward who believe, according to the working of his mighty power,"},"BSB":{"text":"and the surpassing greatness of His power to us who believe. These are in accordance with the working of His mighty strength,"}},"definableWords":["mighty"],"peopleInVerse":[]},"20":{"text":"Which he wrought in Christ, when he raised him from the dead, and set him at his own right hand in the heavenly places,","ref":"Ephesians 1:20","synthesized":"which He exerted in Christ when He raised Him from the dead and seated Him at His right hand in the heavenly realms,","sources":{"KJV":{"text":"Which he wrought in Christ, when he raised him from the dead, and set him at his own right hand in the heavenly places,"},"BSB":{"text":"which He exerted in Christ when He raised Him from the dead and seated Him at His right hand in the heavenly realms,"}},"definableWords":["Christ"],"peopleInVerse":[]},"21":{"text":"Far above all principality, and power, and might, and dominion, and every name that is named, not only in this world, but also in that which is to come:","ref":"Ephesians 1:21","synthesized":"far above all rule and authority, power and dominion, and every name that is named, not only in the present age but also in the one to come.","sources":{"KJV":{"text":"Far above all principality, and power, and might, and dominion, and every name that is named, not only in this world, but also in that which is to come:"},"BSB":{"text":"far above all rule and authority, power and dominion, and every name that is named, not only in the present age but also in the one to come."}},"definableWords":["rule","dominion","name","one"],"peopleInVerse":[]},"22":{"text":"And hath put all things under his feet, and gave him to be the head over all things to the church,","ref":"Ephesians 1:22","synthesized":"And God put everything under His feet and made Him head over everything for the church,","sources":{"KJV":{"text":"And hath put all things under his feet, and gave him to be the head over all things to the church,"},"BSB":{"text":"And God put everything under His feet and made Him head over everything for the church,"}},"definableWords":["God","made","church"],"peopleInVerse":[]},"23":{"text":"Which is his body, the fulness of him that filleth all in all.","ref":"Ephesians 1:23","synthesized":"which is His body, the fullness of Him who fills all in all.","sources":{"KJV":{"text":"Which is his body, the fulness of him that filleth all in all."},"BSB":{"text":"which is His body, the fullness of Him who fills all in all."}},"definableWords":[],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"BY GRACE THROUGH FAITH","verses":{"1":{"text":"And you hath he quickened, who were dead in trespasses and sins;","ref":"Ephesians 2:1","synthesized":"And you were dead in your trespasses and sins,","sources":{"KJV":{"text":"And you hath he quickened, who were dead in trespasses and sins;"},"BSB":{"text":"And you were dead in your trespasses and sins,"}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"Wherein in time past ye walked according to the course of this world, according to the prince of the power of the air, the spirit that now worketh in the children of disobedience:","ref":"Ephesians 2:2","synthesized":"in which you used to walk when you conformed to the ways of this world and of the ruler of the power of the air, the spirit who is now at work in the sons of disobedience.","sources":{"KJV":{"text":"Wherein in time past ye walked according to the course of this world, according to the prince of the power of the air, the spirit that now worketh in the children of disobedience:"},"BSB":{"text":"in which you used to walk when you conformed to the ways of this world and of the ruler of the power of the air, the spirit who is now at work in the sons of disobedience."}},"definableWords":["walk","ruler","spirit","work","sons"],"peopleInVerse":[]},"3":{"text":"Among whom also we all had our conversation in times past in the lusts of our flesh, fulfilling the desires of the flesh and of the mind; and were by nature the children of wrath, even as others.","ref":"Ephesians 2:3","synthesized":"All of us also lived among them at one time, fulfilling the cravings of our flesh and indulging its desires and thoughts. Like the rest, we were by nature children of wrath.","sources":{"KJV":{"text":"Among whom also we all had our conversation in times past in the lusts of our flesh, fulfilling the desires of the flesh and of the mind; and were by nature the children of wrath, even as others."},"BSB":{"text":"All of us also lived among them at one time, fulfilling the cravings of our flesh and indulging its desires and thoughts. Like the rest, we were by nature children of wrath."}},"definableWords":["one","flesh","rest","wrath"],"peopleInVerse":[]},"4":{"text":"But God, who is rich in mercy, for his great love wherewith he loved us,","ref":"Ephesians 2:4","synthesized":"But because of His great love for us, God, who is rich in mercy,","sources":{"KJV":{"text":"But God, who is rich in mercy, for his great love wherewith he loved us,"},"BSB":{"text":"But because of His great love for us, God, who is rich in mercy,"}},"definableWords":["great","love","God","mercy"],"peopleInVerse":[]},"5":{"text":"Even when we were dead in sins, hath quickened us together with Christ, (by grace ye are saved;)","ref":"Ephesians 2:5","synthesized":"made us alive with Christ even when we were dead in our trespasses. It is by grace you have been saved!","sources":{"KJV":{"text":"Even when we were dead in sins, hath quickened us together with Christ, (by grace ye are saved;)"},"BSB":{"text":"made us alive with Christ even when we were dead in our trespasses. It is by grace you have been saved!"}},"definableWords":["made","Christ","grace"],"peopleInVerse":[]},"6":{"text":"And hath raised us up together, and made us sit together in heavenly places in Christ Jesus:","ref":"Ephesians 2:6","synthesized":"And God raised us up with Christ and seated us with Him in the heavenly realms in Christ Jesus,","sources":{"KJV":{"text":"And hath raised us up together, and made us sit together in heavenly places in Christ Jesus:"},"BSB":{"text":"And God raised us up with Christ and seated us with Him in the heavenly realms in Christ Jesus,"}},"definableWords":["God","Christ"],"peopleInVerse":["Jesus"]},"7":{"text":"That in the ages to come he might shew the exceeding riches of his grace in his kindness toward us through Christ Jesus.","ref":"Ephesians 2:7","synthesized":"in order that in the coming ages He might display the surpassing riches of His grace, demonstrated by His kindness to us in Christ Jesus.","sources":{"KJV":{"text":"That in the ages to come he might shew the exceeding riches of his grace in his kindness toward us through Christ Jesus."},"BSB":{"text":"in order that in the coming ages He might display the surpassing riches of His grace, demonstrated by His kindness to us in Christ Jesus."}},"definableWords":["grace","kindness","Christ"],"peopleInVerse":["Jesus"]},"8":{"text":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God:","ref":"Ephesians 2:8","synthesized":"For it is by grace you have been saved through faith, and this not from yourselves; it is the gift of God,","sources":{"KJV":{"text":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God:"},"BSB":{"text":"For it is by grace you have been saved through faith, and this not from yourselves; it is the gift of God,"}},"definableWords":["grace","faith","God"],"peopleInVerse":[]},"9":{"text":"Not of works, lest any man should boast.","ref":"Ephesians 2:9","synthesized":"not by works, so that no one can boast.","sources":{"KJV":{"text":"Not of works, lest any man should boast."},"BSB":{"text":"not by works, so that no one can boast."}},"definableWords":["works","one"],"peopleInVerse":[]},"10":{"text":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them.","ref":"Ephesians 2:10","synthesized":"For we are God’s workmanship, created in Christ Jesus to do good works, which God prepared in advance as our way of life.","sources":{"KJV":{"text":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them."},"BSB":{"text":"For we are God’s workmanship, created in Christ Jesus to do good works, which God prepared in advance as our way of life."}},"definableWords":["God","created","Christ","good","works","way","life"],"peopleInVerse":["Jesus"]},"11":{"text":"Wherefore remember, that ye being in time past Gentiles in the flesh, who are called Uncircumcision by that which is called the Circumcision in the flesh made by hands;","ref":"Ephesians 2:11","synthesized":"Therefore remember that formerly you who are Gentiles in the flesh and called uncircumcised by the so-called circumcision (that done in the body by human hands)—","sources":{"KJV":{"text":"Wherefore remember, that ye being in time past Gentiles in the flesh, who are called Uncircumcision by that which is called the Circumcision in the flesh made by hands;"},"BSB":{"text":"Therefore remember that formerly you who are Gentiles in the flesh and called uncircumcised by the so-called circumcision (that done in the body by human hands)—"}},"definableWords":["remember","flesh","circumcision"],"peopleInVerse":[]},"12":{"text":"That at that time ye were without Christ, being aliens from the commonwealth of Israel, and strangers from the covenants of promise, having no hope, and without God in the world:","ref":"Ephesians 2:12","synthesized":"remember that at that time you were separate from Christ, alienated from the commonwealth of Israel, and strangers to the covenants of the promise, without hope and without God in the world.","sources":{"KJV":{"text":"That at that time ye were without Christ, being aliens from the commonwealth of Israel, and strangers from the covenants of promise, having no hope, and without God in the world:"},"BSB":{"text":"remember that at that time you were separate from Christ, alienated from the commonwealth of Israel, and strangers to the covenants of the promise, without hope and without God in the world."}},"definableWords":["remember","Christ","Israel","promise","hope","God"],"peopleInVerse":[]},"13":{"text":"But now in Christ Jesus ye who sometimes were far off are made nigh by the blood of Christ.","ref":"Ephesians 2:13","synthesized":"But now in Christ Jesus you who once were far away have been brought near through the blood of Christ.","sources":{"KJV":{"text":"But now in Christ Jesus ye who sometimes were far off are made nigh by the blood of Christ."},"BSB":{"text":"But now in Christ Jesus you who once were far away have been brought near through the blood of Christ."}},"definableWords":["Christ","blood"],"peopleInVerse":["Jesus"]},"14":{"text":"For he is our peace, who hath made both one, and hath broken down the middle wall of partition between us;","ref":"Ephesians 2:14","synthesized":"For He Himself is our peace, who has made the two one and has torn down the dividing wall of hostility","sources":{"KJV":{"text":"For he is our peace, who hath made both one, and hath broken down the middle wall of partition between us;"},"BSB":{"text":"For He Himself is our peace, who has made the two one and has torn down the dividing wall of hostility"}},"definableWords":["peace","made","one"],"peopleInVerse":[]},"15":{"text":"Having abolished in his flesh the enmity, even the law of commandments contained in ordinances; for to make in himself of twain one new man, so making peace;","ref":"Ephesians 2:15","synthesized":"by abolishing in His flesh the law of commandments and decrees. He did this to create in Himself one new man out of the two, thus making peace","sources":{"KJV":{"text":"Having abolished in his flesh the enmity, even the law of commandments contained in ordinances; for to make in himself of twain one new man, so making peace;"},"BSB":{"text":"by abolishing in His flesh the law of commandments and decrees. He did this to create in Himself one new man out of the two, thus making peace"}},"definableWords":["flesh","law","create","one","man","peace"],"peopleInVerse":[]},"16":{"text":"And that he might reconcile both unto God in one body by the cross, having slain the enmity thereby:","ref":"Ephesians 2:16","synthesized":"and reconciling both of them to God in one body through the cross, by which He extinguished their hostility.","sources":{"KJV":{"text":"And that he might reconcile both unto God in one body by the cross, having slain the enmity thereby:"},"BSB":{"text":"and reconciling both of them to God in one body through the cross, by which He extinguished their hostility."}},"definableWords":["God","one"],"peopleInVerse":[]},"17":{"text":"And came and preached peace to you which were afar off, and to them that were nigh.","ref":"Ephesians 2:17","synthesized":"He came and preached peace to you who were far away and peace to those who were near.","sources":{"KJV":{"text":"And came and preached peace to you which were afar off, and to them that were nigh."},"BSB":{"text":"He came and preached peace to you who were far away and peace to those who were near."}},"definableWords":["peace"],"peopleInVerse":[]},"18":{"text":"For through him we both have access by one Spirit unto the Father.","ref":"Ephesians 2:18","synthesized":"For through Him we both have access to the Father by one Spirit.","sources":{"KJV":{"text":"For through him we both have access by one Spirit unto the Father."},"BSB":{"text":"For through Him we both have access to the Father by one Spirit."}},"definableWords":["Father","one","Spirit"],"peopleInVerse":[]},"19":{"text":"Now therefore ye are no more strangers and foreigners, but fellowcitizens with the saints, and of the household of God;","ref":"Ephesians 2:19","synthesized":"Therefore you are no longer strangers and foreigners, but fellow citizens with the saints and members of God’s household,","sources":{"KJV":{"text":"Now therefore ye are no more strangers and foreigners, but fellowcitizens with the saints, and of the household of God;"},"BSB":{"text":"Therefore you are no longer strangers and foreigners, but fellow citizens with the saints and members of God’s household,"}},"definableWords":["God"],"peopleInVerse":[]},"20":{"text":"And are built upon the foundation of the apostles and prophets, Jesus Christ himself being the chief corner stone;","ref":"Ephesians 2:20","synthesized":"built on the foundation of the apostles and prophets, with Christ Jesus Himself as the cornerstone.","sources":{"KJV":{"text":"And are built upon the foundation of the apostles and prophets, Jesus Christ himself being the chief corner stone;"},"BSB":{"text":"built on the foundation of the apostles and prophets, with Christ Jesus Himself as the cornerstone."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"21":{"text":"In whom all the building fitly framed together groweth unto an holy temple in the Lord:","ref":"Ephesians 2:21","synthesized":"In Him the whole building is fitted together and grows into a holy temple in the Lord.","sources":{"KJV":{"text":"In whom all the building fitly framed together groweth unto an holy temple in the Lord:"},"BSB":{"text":"In Him the whole building is fitted together and grows into a holy temple in the Lord."}},"definableWords":["holy","temple","Lord"],"peopleInVerse":[]},"22":{"text":"In whom ye also are builded together for an habitation of God through the Spirit.","ref":"Ephesians 2:22","synthesized":"And in Him you too are being built together into a dwelling place for God in His Spirit.","sources":{"KJV":{"text":"In whom ye also are builded together for an habitation of God through the Spirit."},"BSB":{"text":"And in Him you too are being built together into a dwelling place for God in His Spirit."}},"definableWords":["God","Spirit"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"THE MYSTERY HID FROM AGES","verses":{"1":{"text":"For this cause I Paul, the prisoner of Jesus Christ for you Gentiles,","ref":"Ephesians 3:1","synthesized":"For this reason I, Paul, the prisoner of Christ Jesus for the sake of you Gentiles...","sources":{"KJV":{"text":"For this cause I Paul, the prisoner of Jesus Christ for you Gentiles,"},"BSB":{"text":"For this reason I, Paul, the prisoner of Christ Jesus for the sake of you Gentiles..."}},"definableWords":["Christ"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"If ye have heard of the dispensation of the grace of God which is given me to you-ward:","ref":"Ephesians 3:2","synthesized":"Surely you have heard about the stewardship of God’s grace that was given to me for you,","sources":{"KJV":{"text":"If ye have heard of the dispensation of the grace of God which is given me to you-ward:"},"BSB":{"text":"Surely you have heard about the stewardship of God’s grace that was given to me for you,"}},"definableWords":["God","grace"],"peopleInVerse":[]},"3":{"text":"How that by revelation he made known unto me the mystery; (as I wrote afore in few words,","ref":"Ephesians 3:3","synthesized":"that is, the mystery made known to me by revelation, as I have already written briefly.","sources":{"KJV":{"text":"How that by revelation he made known unto me the mystery; (as I wrote afore in few words,"},"BSB":{"text":"that is, the mystery made known to me by revelation, as I have already written briefly."}},"definableWords":["made"],"peopleInVerse":[]},"4":{"text":"Whereby, when ye read, ye may understand my knowledge in the mystery of Christ)","ref":"Ephesians 3:4","synthesized":"In reading this, then, you will be able to understand my insight into the mystery of Christ,","sources":{"KJV":{"text":"Whereby, when ye read, ye may understand my knowledge in the mystery of Christ)"},"BSB":{"text":"In reading this, then, you will be able to understand my insight into the mystery of Christ,"}},"definableWords":["Christ"],"peopleInVerse":[]},"5":{"text":"Which in other ages was not made known unto the sons of men, as it is now revealed unto his holy apostles and prophets by the Spirit;","ref":"Ephesians 3:5","synthesized":"which was not made known to men in other generations as it has now been revealed by the Spirit to God’s holy apostles and prophets.","sources":{"KJV":{"text":"Which in other ages was not made known unto the sons of men, as it is now revealed unto his holy apostles and prophets by the Spirit;"},"BSB":{"text":"which was not made known to men in other generations as it has now been revealed by the Spirit to God’s holy apostles and prophets."}},"definableWords":["made","men","Spirit","God","holy"],"peopleInVerse":[]},"6":{"text":"That the Gentiles should be fellowheirs, and of the same body, and partakers of his promise in Christ by the gospel:","ref":"Ephesians 3:6","synthesized":"This mystery is that through the gospel the Gentiles are fellow heirs, fellow members of the body, and fellow partakers of the promise in Christ Jesus.","sources":{"KJV":{"text":"That the Gentiles should be fellowheirs, and of the same body, and partakers of his promise in Christ by the gospel:"},"BSB":{"text":"This mystery is that through the gospel the Gentiles are fellow heirs, fellow members of the body, and fellow partakers of the promise in Christ Jesus."}},"definableWords":["gospel","promise","Christ"],"peopleInVerse":["Jesus"]},"7":{"text":"Whereof I was made a minister, according to the gift of the grace of God given unto me by the effectual working of his power.","ref":"Ephesians 3:7","synthesized":"I became a servant of this gospel by the gift of God’s grace, given me through the working of His power.","sources":{"KJV":{"text":"Whereof I was made a minister, according to the gift of the grace of God given unto me by the effectual working of his power."},"BSB":{"text":"I became a servant of this gospel by the gift of God’s grace, given me through the working of His power."}},"definableWords":["servant","gospel","God","grace"],"peopleInVerse":[]},"8":{"text":"Unto me, who am less than the least of all saints, is this grace given, that I should preach among the Gentiles the unsearchable riches of Christ;","ref":"Ephesians 3:8","synthesized":"Though I am less than the least of all the saints, this grace was given me: to preach to the Gentiles the unsearchable riches of Christ,","sources":{"KJV":{"text":"Unto me, who am less than the least of all saints, is this grace given, that I should preach among the Gentiles the unsearchable riches of Christ;"},"BSB":{"text":"Though I am less than the least of all the saints, this grace was given me: to preach to the Gentiles the unsearchable riches of Christ,"}},"definableWords":["grace","Christ"],"peopleInVerse":[]},"9":{"text":"And to make all men see what is the fellowship of the mystery, which from the beginning of the world hath been hid in God, who created all things by Jesus Christ:","ref":"Ephesians 3:9","synthesized":"and to illuminate for everyone the stewardship of this mystery, which for ages past was kept hidden in God, who created all things.","sources":{"KJV":{"text":"And to make all men see what is the fellowship of the mystery, which from the beginning of the world hath been hid in God, who created all things by Jesus Christ:"},"BSB":{"text":"and to illuminate for everyone the stewardship of this mystery, which for ages past was kept hidden in God, who created all things."}},"definableWords":["God","created"],"peopleInVerse":[]},"10":{"text":"To the intent that now unto the principalities and powers in heavenly places might be known by the church the manifold wisdom of God,","ref":"Ephesians 3:10","synthesized":"His purpose was that now, through the church, the manifold wisdom of God should be made known to the rulers and authorities in the heavenly realms,","sources":{"KJV":{"text":"To the intent that now unto the principalities and powers in heavenly places might be known by the church the manifold wisdom of God,"},"BSB":{"text":"His purpose was that now, through the church, the manifold wisdom of God should be made known to the rulers and authorities in the heavenly realms,"}},"definableWords":["church","wisdom","God","made"],"peopleInVerse":[]},"11":{"text":"According to the eternal purpose which he purposed in Christ Jesus our Lord:","ref":"Ephesians 3:11","synthesized":"according to the eternal purpose that He accomplished in Christ Jesus our Lord.","sources":{"KJV":{"text":"According to the eternal purpose which he purposed in Christ Jesus our Lord:"},"BSB":{"text":"according to the eternal purpose that He accomplished in Christ Jesus our Lord."}},"definableWords":["eternal","Christ","Lord"],"peopleInVerse":["Jesus"]},"12":{"text":"In whom we have boldness and access with confidence by the faith of him.","ref":"Ephesians 3:12","synthesized":"In Him and through faith in Him we may enter God’s presence with boldness and confidence.","sources":{"KJV":{"text":"In whom we have boldness and access with confidence by the faith of him."},"BSB":{"text":"In Him and through faith in Him we may enter God’s presence with boldness and confidence."}},"definableWords":["faith","God"],"peopleInVerse":[]},"13":{"text":"Wherefore I desire that ye faint not at my tribulations for you, which is your glory.","ref":"Ephesians 3:13","synthesized":"So I ask you not to be discouraged because of my sufferings for you, which are your glory.","sources":{"KJV":{"text":"Wherefore I desire that ye faint not at my tribulations for you, which is your glory."},"BSB":{"text":"So I ask you not to be discouraged because of my sufferings for you, which are your glory."}},"definableWords":["glory"],"peopleInVerse":[]},"14":{"text":"For this cause I bow my knees unto the Father of our Lord Jesus Christ,","ref":"Ephesians 3:14","synthesized":"... for this reason I bow my knees before the Father,","sources":{"KJV":{"text":"For this cause I bow my knees unto the Father of our Lord Jesus Christ,"},"BSB":{"text":"... for this reason I bow my knees before the Father,"}},"definableWords":["Father"],"peopleInVerse":[]},"15":{"text":"Of whom the whole family in heaven and earth is named,","ref":"Ephesians 3:15","synthesized":"from whom every family in heaven and on earth derives its name.","sources":{"KJV":{"text":"Of whom the whole family in heaven and earth is named,"},"BSB":{"text":"from whom every family in heaven and on earth derives its name."}},"definableWords":["family","heaven","earth","name"],"peopleInVerse":[]},"16":{"text":"That he would grant you, according to the riches of his glory, to be strengthened with might by his Spirit in the inner man;","ref":"Ephesians 3:16","synthesized":"I ask that out of the riches of His glory He may strengthen you with power through His Spirit in your inner being,","sources":{"KJV":{"text":"That he would grant you, according to the riches of his glory, to be strengthened with might by his Spirit in the inner man;"},"BSB":{"text":"I ask that out of the riches of His glory He may strengthen you with power through His Spirit in your inner being,"}},"definableWords":["glory","Spirit"],"peopleInVerse":[]},"17":{"text":"That Christ may dwell in your hearts by faith; that ye, being rooted and grounded in love,","ref":"Ephesians 3:17","synthesized":"so that Christ may dwell in your hearts through faith. Then you, being rooted and grounded in love,","sources":{"KJV":{"text":"That Christ may dwell in your hearts by faith; that ye, being rooted and grounded in love,"},"BSB":{"text":"so that Christ may dwell in your hearts through faith. Then you, being rooted and grounded in love,"}},"definableWords":["Christ","faith","love"],"peopleInVerse":[]},"18":{"text":"May be able to comprehend with all saints what is the breadth, and length, and depth, and height;","ref":"Ephesians 3:18","synthesized":"will have power, together with all the saints, to comprehend the length and width and height and depth","sources":{"KJV":{"text":"May be able to comprehend with all saints what is the breadth, and length, and depth, and height;"},"BSB":{"text":"will have power, together with all the saints, to comprehend the length and width and height and depth"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"And to know the love of Christ, which passeth knowledge, that ye might be filled with all the fulness of God.","ref":"Ephesians 3:19","synthesized":"of the love of Christ, and to know this love that surpasses knowledge, that you may be filled with all the fullness of God.","sources":{"KJV":{"text":"And to know the love of Christ, which passeth knowledge, that ye might be filled with all the fulness of God."},"BSB":{"text":"of the love of Christ, and to know this love that surpasses knowledge, that you may be filled with all the fullness of God."}},"definableWords":["love","Christ","knowledge","God"],"peopleInVerse":[]},"20":{"text":"Now unto him that is able to do exceeding abundantly above all that we ask or think, according to the power that worketh in us,","ref":"Ephesians 3:20","synthesized":"Now to Him who is able to do immeasurably more than all we ask or imagine, according to His power that is at work within us,","sources":{"KJV":{"text":"Now unto him that is able to do exceeding abundantly above all that we ask or think, according to the power that worketh in us,"},"BSB":{"text":"Now to Him who is able to do immeasurably more than all we ask or imagine, according to His power that is at work within us,"}},"definableWords":["or","work"],"peopleInVerse":[]},"21":{"text":"Unto him be glory in the church by Christ Jesus throughout all ages, world without end. Amen.","ref":"Ephesians 3:21","synthesized":"to Him be the glory in the church and in Christ Jesus throughout all generations, forever and ever. Amen.","sources":{"KJV":{"text":"Unto him be glory in the church by Christ Jesus throughout all ages, world without end. Amen."},"BSB":{"text":"to Him be the glory in the church and in Christ Jesus throughout all generations, forever and ever. Amen."}},"definableWords":["glory","church","Christ"],"peopleInVerse":["Jesus"]}}},"4":{"chapter":"4","title":"ONE BODY, ONE SPIRIT, ONE LORD","verses":{"1":{"text":"I therefore, the prisoner of the Lord, beseech you that ye walk worthy of the vocation wherewith ye are called,","ref":"Ephesians 4:1","synthesized":"As a prisoner in the Lord, then, I urge you to walk in a manner worthy of the calling you have received:","sources":{"KJV":{"text":"I therefore, the prisoner of the Lord, beseech you that ye walk worthy of the vocation wherewith ye are called,"},"BSB":{"text":"As a prisoner in the Lord, then, I urge you to walk in a manner worthy of the calling you have received:"}},"definableWords":["Lord","walk"],"peopleInVerse":[]},"2":{"text":"With all lowliness and meekness, with longsuffering, forbearing one another in love;","ref":"Ephesians 4:2","synthesized":"with all humility and gentleness, with patience, bearing with one another in love,","sources":{"KJV":{"text":"With all lowliness and meekness, with longsuffering, forbearing one another in love;"},"BSB":{"text":"with all humility and gentleness, with patience, bearing with one another in love,"}},"definableWords":["patience","one","love"],"peopleInVerse":[]},"3":{"text":"Endeavouring to keep the unity of the Spirit in the bond of peace.","ref":"Ephesians 4:3","synthesized":"and with diligence to preserve the unity of the Spirit through the bond of peace.","sources":{"KJV":{"text":"Endeavouring to keep the unity of the Spirit in the bond of peace."},"BSB":{"text":"and with diligence to preserve the unity of the Spirit through the bond of peace."}},"definableWords":["Spirit","peace"],"peopleInVerse":[]},"4":{"text":"There is one body, and one Spirit, even as ye are called in one hope of your calling;","ref":"Ephesians 4:4","synthesized":"There is one body and one Spirit, just as you were called to one hope when you were called;","sources":{"KJV":{"text":"There is one body, and one Spirit, even as ye are called in one hope of your calling;"},"BSB":{"text":"There is one body and one Spirit, just as you were called to one hope when you were called;"}},"definableWords":["one","Spirit","hope"],"peopleInVerse":[]},"5":{"text":"One Lord, one faith, one baptism,","ref":"Ephesians 4:5","synthesized":"one Lord, one faith, one baptism;","sources":{"KJV":{"text":"One Lord, one faith, one baptism,"},"BSB":{"text":"one Lord, one faith, one baptism;"}},"definableWords":["one","Lord","faith","baptism"],"peopleInVerse":[]},"6":{"text":"One God and Father of all, who is above all, and through all, and in you all.","ref":"Ephesians 4:6","synthesized":"one God and Father of all, who is over all and through all and in all.","sources":{"KJV":{"text":"One God and Father of all, who is above all, and through all, and in you all."},"BSB":{"text":"one God and Father of all, who is over all and through all and in all."}},"definableWords":["one","God","Father"],"peopleInVerse":[]},"7":{"text":"But unto every one of us is given grace according to the measure of the gift of Christ.","ref":"Ephesians 4:7","synthesized":"Now to each one of us grace has been given according to the measure of the gift of Christ.","sources":{"KJV":{"text":"But unto every one of us is given grace according to the measure of the gift of Christ."},"BSB":{"text":"Now to each one of us grace has been given according to the measure of the gift of Christ."}},"definableWords":["one","grace","Christ"],"peopleInVerse":[]},"8":{"text":"Wherefore he saith, When he ascended up on high, he led captivity captive, and gave gifts unto men.","ref":"Ephesians 4:8","synthesized":"This is why it says:  “When He ascended on high, He led captives away, and gave gifts to men.”","sources":{"KJV":{"text":"Wherefore he saith, When he ascended up on high, he led captivity captive, and gave gifts unto men."},"BSB":{"text":"This is why it says:  “When He ascended on high, He led captives away, and gave gifts to men.”"}},"definableWords":["men"],"peopleInVerse":[]},"9":{"text":"(Now that he ascended, what is it but that he also descended first into the lower parts of the earth?","ref":"Ephesians 4:9","synthesized":"What does “He ascended” mean, except that He also descended to the lower parts of the earth?","sources":{"KJV":{"text":"(Now that he ascended, what is it but that he also descended first into the lower parts of the earth?"},"BSB":{"text":"What does “He ascended” mean, except that He also descended to the lower parts of the earth?"}},"definableWords":["earth"],"peopleInVerse":[]},"10":{"text":"He that descended is the same also that ascended up far above all heavens, that he might fill all things.)","ref":"Ephesians 4:10","synthesized":"He who descended is the very One who ascended above all the heavens, in order to fill all things.","sources":{"KJV":{"text":"He that descended is the same also that ascended up far above all heavens, that he might fill all things.)"},"BSB":{"text":"He who descended is the very One who ascended above all the heavens, in order to fill all things."}},"definableWords":["one","heavens","fill"],"peopleInVerse":[]},"11":{"text":"And he gave some, apostles; and some, prophets; and some, evangelists; and some, pastors and teachers;","ref":"Ephesians 4:11","synthesized":"And it was He who gave some to be apostles, some to be prophets, some to be evangelists, and some to be pastors and teachers,","sources":{"KJV":{"text":"And he gave some, apostles; and some, prophets; and some, evangelists; and some, pastors and teachers;"},"BSB":{"text":"And it was He who gave some to be apostles, some to be prophets, some to be evangelists, and some to be pastors and teachers,"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For the perfecting of the saints, for the work of the ministry, for the edifying of the body of Christ:","ref":"Ephesians 4:12","synthesized":"to equip the saints for works of ministry and to build up the body of Christ,","sources":{"KJV":{"text":"For the perfecting of the saints, for the work of the ministry, for the edifying of the body of Christ:"},"BSB":{"text":"to equip the saints for works of ministry and to build up the body of Christ,"}},"definableWords":["works","Christ"],"peopleInVerse":[]},"13":{"text":"Till we all come in the unity of the faith, and of the knowledge of the Son of God, unto a perfect man, unto the measure of the stature of the fulness of Christ:","ref":"Ephesians 4:13","synthesized":"until we all reach unity in the faith and in the knowledge of the Son of God, as we mature to the full measure of the stature of Christ.","sources":{"KJV":{"text":"Till we all come in the unity of the faith, and of the knowledge of the Son of God, unto a perfect man, unto the measure of the stature of the fulness of Christ:"},"BSB":{"text":"until we all reach unity in the faith and in the knowledge of the Son of God, as we mature to the full measure of the stature of Christ."}},"definableWords":["faith","knowledge","Son","God","Christ"],"peopleInVerse":[]},"14":{"text":"That we henceforth be no more children, tossed to and fro, and carried about with every wind of doctrine, by the sleight of men, and cunning craftiness, whereby they lie in wait to deceive;","ref":"Ephesians 4:14","synthesized":"Then we will no longer be infants, tossed about by the waves and carried around by every wind of teaching and by the clever cunning of men in their deceitful scheming.","sources":{"KJV":{"text":"That we henceforth be no more children, tossed to and fro, and carried about with every wind of doctrine, by the sleight of men, and cunning craftiness, whereby they lie in wait to deceive;"},"BSB":{"text":"Then we will no longer be infants, tossed about by the waves and carried around by every wind of teaching and by the clever cunning of men in their deceitful scheming."}},"definableWords":["men"],"peopleInVerse":[]},"15":{"text":"But speaking the truth in love, may grow up into him in all things, which is the head, even Christ:","ref":"Ephesians 4:15","synthesized":"Instead, speaking the truth in love, we will in all things grow up into Christ Himself, who is the head.","sources":{"KJV":{"text":"But speaking the truth in love, may grow up into him in all things, which is the head, even Christ:"},"BSB":{"text":"Instead, speaking the truth in love, we will in all things grow up into Christ Himself, who is the head."}},"definableWords":["truth","love","Christ"],"peopleInVerse":[]},"16":{"text":"From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the measure of every part, maketh increase of the body unto the edifying of itself in love.","ref":"Ephesians 4:16","synthesized":"From Him the whole body, fitted and held together by every supporting ligament, grows and builds itself up in love through the work of each individual part.","sources":{"KJV":{"text":"From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the measure of every part, maketh increase of the body unto the edifying of itself in love."},"BSB":{"text":"From Him the whole body, fitted and held together by every supporting ligament, grows and builds itself up in love through the work of each individual part."}},"definableWords":["love","work"],"peopleInVerse":[]},"17":{"text":"This I say therefore, and testify in the Lord, that ye henceforth walk not as other Gentiles walk, in the vanity of their mind,","ref":"Ephesians 4:17","synthesized":"So I tell you this, and insist on it in the Lord, that you must no longer walk as the Gentiles do, in the futility of their thinking.","sources":{"KJV":{"text":"This I say therefore, and testify in the Lord, that ye henceforth walk not as other Gentiles walk, in the vanity of their mind,"},"BSB":{"text":"So I tell you this, and insist on it in the Lord, that you must no longer walk as the Gentiles do, in the futility of their thinking."}},"definableWords":["Lord","walk"],"peopleInVerse":[]},"18":{"text":"Having the understanding darkened, being alienated from the life of God through the ignorance that is in them, because of the blindness of their heart:","ref":"Ephesians 4:18","synthesized":"They are darkened in their understanding and alienated from the life of God because of the ignorance that is in them due to the hardness of their hearts.","sources":{"KJV":{"text":"Having the understanding darkened, being alienated from the life of God through the ignorance that is in them, because of the blindness of their heart:"},"BSB":{"text":"They are darkened in their understanding and alienated from the life of God because of the ignorance that is in them due to the hardness of their hearts."}},"definableWords":["life","God"],"peopleInVerse":[]},"19":{"text":"Who being past feeling have given themselves over unto lasciviousness, to work all uncleanness with greediness.","ref":"Ephesians 4:19","synthesized":"Having lost all sense of shame, they have given themselves over to sensuality for the practice of every kind of impurity, with a craving for more.","sources":{"KJV":{"text":"Who being past feeling have given themselves over unto lasciviousness, to work all uncleanness with greediness."},"BSB":{"text":"Having lost all sense of shame, they have given themselves over to sensuality for the practice of every kind of impurity, with a craving for more."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"But ye have not so learned Christ;","ref":"Ephesians 4:20","synthesized":"But this is not the way you came to know Christ.","sources":{"KJV":{"text":"But ye have not so learned Christ;"},"BSB":{"text":"But this is not the way you came to know Christ."}},"definableWords":["way","Christ"],"peopleInVerse":[]},"21":{"text":"If so be that ye have heard him, and have been taught by him, as the truth is in Jesus:","ref":"Ephesians 4:21","synthesized":"Surely you heard of Him and were taught in Him—in keeping with the truth that is in Jesus—","sources":{"KJV":{"text":"If so be that ye have heard him, and have been taught by him, as the truth is in Jesus:"},"BSB":{"text":"Surely you heard of Him and were taught in Him—in keeping with the truth that is in Jesus—"}},"definableWords":["truth"],"peopleInVerse":["Jesus"]},"22":{"text":"That ye put off concerning the former conversation the old man, which is corrupt according to the deceitful lusts;","ref":"Ephesians 4:22","synthesized":"to put off your former way of life, your old self, which is being corrupted by its deceitful desires;","sources":{"KJV":{"text":"That ye put off concerning the former conversation the old man, which is corrupt according to the deceitful lusts;"},"BSB":{"text":"to put off your former way of life, your old self, which is being corrupted by its deceitful desires;"}},"definableWords":["way","life"],"peopleInVerse":[]},"23":{"text":"And be renewed in the spirit of your mind;","ref":"Ephesians 4:23","synthesized":"to be renewed in the spirit of your minds;","sources":{"KJV":{"text":"And be renewed in the spirit of your mind;"},"BSB":{"text":"to be renewed in the spirit of your minds;"}},"definableWords":["spirit"],"peopleInVerse":[]},"24":{"text":"And that ye put on the new man, which after God is created in righteousness and true holiness.","ref":"Ephesians 4:24","synthesized":"and to put on the new self, created to be like God in true righteousness and holiness.","sources":{"KJV":{"text":"And that ye put on the new man, which after God is created in righteousness and true holiness."},"BSB":{"text":"and to put on the new self, created to be like God in true righteousness and holiness."}},"definableWords":["created","God","righteousness"],"peopleInVerse":[]},"25":{"text":"Wherefore putting away lying, speak every man truth with his neighbour: for we are members one of another.","ref":"Ephesians 4:25","synthesized":"Therefore each of you must put off falsehood and speak truthfully to his neighbor, for we are all members of one another.","sources":{"KJV":{"text":"Wherefore putting away lying, speak every man truth with his neighbour: for we are members one of another."},"BSB":{"text":"Therefore each of you must put off falsehood and speak truthfully to his neighbor, for we are all members of one another."}},"definableWords":["one"],"peopleInVerse":[]},"26":{"text":"Be ye angry, and sin not: let not the sun go down upon your wrath:","ref":"Ephesians 4:26","synthesized":"“Be angry, yet do not sin.” Do not let the sun set upon your anger,","sources":{"KJV":{"text":"Be ye angry, and sin not: let not the sun go down upon your wrath:"},"BSB":{"text":"“Be angry, yet do not sin.” Do not let the sun set upon your anger,"}},"definableWords":["sin","anger"],"peopleInVerse":[]},"27":{"text":"Neither give place to the devil.","ref":"Ephesians 4:27","synthesized":"and do not give the devil a foothold.","sources":{"KJV":{"text":"Neither give place to the devil."},"BSB":{"text":"and do not give the devil a foothold."}},"definableWords":["devil"],"peopleInVerse":[]},"28":{"text":"Let him that stole steal no more: but rather let him labour, working with his hands the thing which is good, that he may have to give to him that needeth.","ref":"Ephesians 4:28","synthesized":"He who has been stealing must steal no longer, but must work, doing good with his own hands, that he may have something to share with the one in need.","sources":{"KJV":{"text":"Let him that stole steal no more: but rather let him labour, working with his hands the thing which is good, that he may have to give to him that needeth."},"BSB":{"text":"He who has been stealing must steal no longer, but must work, doing good with his own hands, that he may have something to share with the one in need."}},"definableWords":["work","good","one"],"peopleInVerse":[]},"29":{"text":"Let no corrupt communication proceed out of your mouth, but that which is good to the use of edifying, that it may minister grace unto the hearers.","ref":"Ephesians 4:29","synthesized":"Let no unwholesome talk come out of your mouths, but only what is helpful for building up the one in need and bringing grace to those who listen.","sources":{"KJV":{"text":"Let no corrupt communication proceed out of your mouth, but that which is good to the use of edifying, that it may minister grace unto the hearers."},"BSB":{"text":"Let no unwholesome talk come out of your mouths, but only what is helpful for building up the one in need and bringing grace to those who listen."}},"definableWords":["one","grace"],"peopleInVerse":[]},"30":{"text":"And grieve not the holy Spirit of God, whereby ye are sealed unto the day of redemption.","ref":"Ephesians 4:30","synthesized":"And do not grieve the Holy Spirit of God, in whom you were sealed for the day of redemption.","sources":{"KJV":{"text":"And grieve not the holy Spirit of God, whereby ye are sealed unto the day of redemption."},"BSB":{"text":"And do not grieve the Holy Spirit of God, in whom you were sealed for the day of redemption."}},"definableWords":["holy","Spirit","God","day","redemption"],"peopleInVerse":[]},"31":{"text":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice:","ref":"Ephesians 4:31","synthesized":"Get rid of all bitterness, rage and anger, outcry and slander, along with every form of malice.","sources":{"KJV":{"text":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice:"},"BSB":{"text":"Get rid of all bitterness, rage and anger, outcry and slander, along with every form of malice."}},"definableWords":["anger","form"],"peopleInVerse":[]},"32":{"text":"And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ’s sake hath forgiven you.","ref":"Ephesians 4:32","synthesized":"Be kind and tenderhearted to one another, forgiving each other just as in Christ God forgave you.","sources":{"KJV":{"text":"And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ’s sake hath forgiven you."},"BSB":{"text":"Be kind and tenderhearted to one another, forgiving each other just as in Christ God forgave you."}},"definableWords":["one","Christ","God"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"BE FILLED WITH THE SPIRIT","verses":{"1":{"text":"Be ye therefore followers of God, as dear children;","ref":"Ephesians 5:1","synthesized":"Be imitators of God, therefore, as beloved children,","sources":{"KJV":{"text":"Be ye therefore followers of God, as dear children;"},"BSB":{"text":"Be imitators of God, therefore, as beloved children,"}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"And walk in love, as Christ also hath loved us, and hath given himself for us an offering and a sacrifice to God for a sweetsmelling savour.","ref":"Ephesians 5:2","synthesized":"and walk in love, just as Christ loved us and gave Himself up for us as a fragrant sacrificial offering to God.","sources":{"KJV":{"text":"And walk in love, as Christ also hath loved us, and hath given himself for us an offering and a sacrifice to God for a sweetsmelling savour."},"BSB":{"text":"and walk in love, just as Christ loved us and gave Himself up for us as a fragrant sacrificial offering to God."}},"definableWords":["walk","love","Christ","offering","God"],"peopleInVerse":[]},"3":{"text":"But fornication, and all uncleanness, or covetousness, let it not be once named among you, as becometh saints;","ref":"Ephesians 5:3","synthesized":"But among you, as is proper among the saints, there must not be even a hint of sexual immorality, or of any kind of impurity, or of greed.","sources":{"KJV":{"text":"But fornication, and all uncleanness, or covetousness, let it not be once named among you, as becometh saints;"},"BSB":{"text":"But among you, as is proper among the saints, there must not be even a hint of sexual immorality, or of any kind of impurity, or of greed."}},"definableWords":["or"],"peopleInVerse":[]},"4":{"text":"Neither filthiness, nor foolish talking, nor jesting, which are not convenient: but rather giving of thanks.","ref":"Ephesians 5:4","synthesized":"Nor should there be obscenity, foolish talk, or crude joking, which are out of character, but rather thanksgiving.","sources":{"KJV":{"text":"Neither filthiness, nor foolish talking, nor jesting, which are not convenient: but rather giving of thanks."},"BSB":{"text":"Nor should there be obscenity, foolish talk, or crude joking, which are out of character, but rather thanksgiving."}},"definableWords":["or"],"peopleInVerse":[]},"5":{"text":"For this ye know, that no whoremonger, nor unclean person, nor covetous man, who is an idolater, hath any inheritance in the kingdom of Christ and of God.","ref":"Ephesians 5:5","synthesized":"For of this you can be sure: No immoral, impure, or greedy person (that is, an idolater), has any inheritance in the kingdom of Christ and of God.","sources":{"KJV":{"text":"For this ye know, that no whoremonger, nor unclean person, nor covetous man, who is an idolater, hath any inheritance in the kingdom of Christ and of God."},"BSB":{"text":"For of this you can be sure: No immoral, impure, or greedy person (that is, an idolater), has any inheritance in the kingdom of Christ and of God."}},"definableWords":["or","kingdom","Christ","God"],"peopleInVerse":[]},"6":{"text":"Let no man deceive you with vain words: for because of these things cometh the wrath of God upon the children of disobedience.","ref":"Ephesians 5:6","synthesized":"Let no one deceive you with empty words, for because of such things the wrath of God is coming on the sons of disobedience.","sources":{"KJV":{"text":"Let no man deceive you with vain words: for because of these things cometh the wrath of God upon the children of disobedience."},"BSB":{"text":"Let no one deceive you with empty words, for because of such things the wrath of God is coming on the sons of disobedience."}},"definableWords":["one","wrath","God","sons"],"peopleInVerse":[]},"7":{"text":"Be not ye therefore partakers with them.","ref":"Ephesians 5:7","synthesized":"Therefore do not be partakers with them.","sources":{"KJV":{"text":"Be not ye therefore partakers with them."},"BSB":{"text":"Therefore do not be partakers with them."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For ye were sometimes darkness, but now are ye light in the Lord: walk as children of light:","ref":"Ephesians 5:8","synthesized":"For you were once darkness, but now you are light in the Lord. Walk as children of light,","sources":{"KJV":{"text":"For ye were sometimes darkness, but now are ye light in the Lord: walk as children of light:"},"BSB":{"text":"For you were once darkness, but now you are light in the Lord. Walk as children of light,"}},"definableWords":["darkness","light","Lord","walk"],"peopleInVerse":[]},"9":{"text":"(For the fruit of the Spirit is in all goodness and righteousness and truth;)","ref":"Ephesians 5:9","synthesized":"for the fruit of the light consists in all goodness, righteousness, and truth.","sources":{"KJV":{"text":"(For the fruit of the Spirit is in all goodness and righteousness and truth;)"},"BSB":{"text":"for the fruit of the light consists in all goodness, righteousness, and truth."}},"definableWords":["light","righteousness","truth"],"peopleInVerse":[]},"10":{"text":"Proving what is acceptable unto the Lord.","ref":"Ephesians 5:10","synthesized":"Test and prove what pleases the Lord.","sources":{"KJV":{"text":"Proving what is acceptable unto the Lord."},"BSB":{"text":"Test and prove what pleases the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"11":{"text":"And have no fellowship with the unfruitful works of darkness, but rather reprove them.","ref":"Ephesians 5:11","synthesized":"Have no fellowship with the fruitless deeds of darkness, but rather expose them.","sources":{"KJV":{"text":"And have no fellowship with the unfruitful works of darkness, but rather reprove them."},"BSB":{"text":"Have no fellowship with the fruitless deeds of darkness, but rather expose them."}},"definableWords":["darkness"],"peopleInVerse":[]},"12":{"text":"For it is a shame even to speak of those things which are done of them in secret.","ref":"Ephesians 5:12","synthesized":"For it is shameful even to mention what the disobedient do in secret.","sources":{"KJV":{"text":"For it is a shame even to speak of those things which are done of them in secret."},"BSB":{"text":"For it is shameful even to mention what the disobedient do in secret."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"But all things that are reproved are made manifest by the light: for whatsoever doth make manifest is light.","ref":"Ephesians 5:13","synthesized":"But everything exposed by the light becomes visible, for everything that is illuminated becomes a light itself.","sources":{"KJV":{"text":"But all things that are reproved are made manifest by the light: for whatsoever doth make manifest is light."},"BSB":{"text":"But everything exposed by the light becomes visible, for everything that is illuminated becomes a light itself."}},"definableWords":["light"],"peopleInVerse":[]},"14":{"text":"Wherefore he saith, Awake thou that sleepest, and arise from the dead, and Christ shall give thee light.","ref":"Ephesians 5:14","synthesized":"So it is said:  “Wake up, O sleeper, rise up from the dead, and Christ will shine on you.”","sources":{"KJV":{"text":"Wherefore he saith, Awake thou that sleepest, and arise from the dead, and Christ shall give thee light."},"BSB":{"text":"So it is said:  “Wake up, O sleeper, rise up from the dead, and Christ will shine on you.”"}},"definableWords":["Christ"],"peopleInVerse":[]},"15":{"text":"See then that ye walk circumspectly, not as fools, but as wise,","ref":"Ephesians 5:15","synthesized":"Pay careful attention, then, to how you walk, not as unwise but as wise,","sources":{"KJV":{"text":"See then that ye walk circumspectly, not as fools, but as wise,"},"BSB":{"text":"Pay careful attention, then, to how you walk, not as unwise but as wise,"}},"definableWords":["walk"],"peopleInVerse":[]},"16":{"text":"Redeeming the time, because the days are evil.","ref":"Ephesians 5:16","synthesized":"redeeming the time, because the days are evil.","sources":{"KJV":{"text":"Redeeming the time, because the days are evil."},"BSB":{"text":"redeeming the time, because the days are evil."}},"definableWords":["days","evil"],"peopleInVerse":[]},"17":{"text":"Wherefore be ye not unwise, but understanding what the will of the Lord is.","ref":"Ephesians 5:17","synthesized":"Therefore do not be foolish, but understand what the Lord’s will is.","sources":{"KJV":{"text":"Wherefore be ye not unwise, but understanding what the will of the Lord is."},"BSB":{"text":"Therefore do not be foolish, but understand what the Lord’s will is."}},"definableWords":["Lord"],"peopleInVerse":[]},"18":{"text":"And be not drunk with wine, wherein is excess; but be filled with the Spirit;","ref":"Ephesians 5:18","synthesized":"Do not get drunk on wine, which leads to reckless indiscretion. Instead, be filled with the Spirit.","sources":{"KJV":{"text":"And be not drunk with wine, wherein is excess; but be filled with the Spirit;"},"BSB":{"text":"Do not get drunk on wine, which leads to reckless indiscretion. Instead, be filled with the Spirit."}},"definableWords":["Spirit"],"peopleInVerse":[]},"19":{"text":"Speaking to yourselves in psalms and hymns and spiritual songs, singing and making melody in your heart to the Lord;","ref":"Ephesians 5:19","synthesized":"Speak to one another with psalms, hymns, and spiritual songs. Sing and make music in your hearts to the Lord,","sources":{"KJV":{"text":"Speaking to yourselves in psalms and hymns and spiritual songs, singing and making melody in your heart to the Lord;"},"BSB":{"text":"Speak to one another with psalms, hymns, and spiritual songs. Sing and make music in your hearts to the Lord,"}},"definableWords":["one","make","Lord"],"peopleInVerse":[]},"20":{"text":"Giving thanks always for all things unto God and the Father in the name of our Lord Jesus Christ;","ref":"Ephesians 5:20","synthesized":"always giving thanks to God the Father for everything in the name of our Lord Jesus Christ.","sources":{"KJV":{"text":"Giving thanks always for all things unto God and the Father in the name of our Lord Jesus Christ;"},"BSB":{"text":"always giving thanks to God the Father for everything in the name of our Lord Jesus Christ."}},"definableWords":["God","Father","name","Lord","Christ"],"peopleInVerse":["Jesus"]},"21":{"text":"Submitting yourselves one to another in the fear of God.","ref":"Ephesians 5:21","synthesized":"Submit to one another out of reverence for Christ.","sources":{"KJV":{"text":"Submitting yourselves one to another in the fear of God."},"BSB":{"text":"Submit to one another out of reverence for Christ."}},"definableWords":["one","Christ"],"peopleInVerse":[]},"22":{"text":"Wives, submit yourselves unto your own husbands, as unto the Lord.","ref":"Ephesians 5:22","synthesized":"Wives, submit to your husbands as to the Lord.","sources":{"KJV":{"text":"Wives, submit yourselves unto your own husbands, as unto the Lord."},"BSB":{"text":"Wives, submit to your husbands as to the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"23":{"text":"For the husband is the head of the wife, even as Christ is the head of the church: and he is the saviour of the body.","ref":"Ephesians 5:23","synthesized":"For the husband is the head of the wife as Christ is the head of the church, His body, of which He is the Savior.","sources":{"KJV":{"text":"For the husband is the head of the wife, even as Christ is the head of the church: and he is the saviour of the body."},"BSB":{"text":"For the husband is the head of the wife as Christ is the head of the church, His body, of which He is the Savior."}},"definableWords":["husband","wife","Christ","church"],"peopleInVerse":[]},"24":{"text":"Therefore as the church is subject unto Christ, so let the wives be to their own husbands in every thing.","ref":"Ephesians 5:24","synthesized":"Now as the church submits to Christ, so also wives should submit to their husbands in everything.","sources":{"KJV":{"text":"Therefore as the church is subject unto Christ, so let the wives be to their own husbands in every thing."},"BSB":{"text":"Now as the church submits to Christ, so also wives should submit to their husbands in everything."}},"definableWords":["church","Christ"],"peopleInVerse":[]},"25":{"text":"Husbands, love your wives, even as Christ also loved the church, and gave himself for it;","ref":"Ephesians 5:25","synthesized":"Husbands, love your wives, just as Christ loved the church and gave Himself up for her","sources":{"KJV":{"text":"Husbands, love your wives, even as Christ also loved the church, and gave himself for it;"},"BSB":{"text":"Husbands, love your wives, just as Christ loved the church and gave Himself up for her"}},"definableWords":["love","Christ","church"],"peopleInVerse":[]},"26":{"text":"That he might sanctify and cleanse it with the washing of water by the word,","ref":"Ephesians 5:26","synthesized":"to sanctify her, cleansing her by the washing with water through the word,","sources":{"KJV":{"text":"That he might sanctify and cleanse it with the washing of water by the word,"},"BSB":{"text":"to sanctify her, cleansing her by the washing with water through the word,"}},"definableWords":["water","word"],"peopleInVerse":[]},"27":{"text":"That he might present it to himself a glorious church, not having spot, or wrinkle, or any such thing; but that it should be holy and without blemish.","ref":"Ephesians 5:27","synthesized":"and to present her to Himself as a glorious church, without stain or wrinkle or any such blemish, but holy and blameless.","sources":{"KJV":{"text":"That he might present it to himself a glorious church, not having spot, or wrinkle, or any such thing; but that it should be holy and without blemish."},"BSB":{"text":"and to present her to Himself as a glorious church, without stain or wrinkle or any such blemish, but holy and blameless."}},"definableWords":["church","or","holy"],"peopleInVerse":[]},"28":{"text":"So ought men to love their wives as their own bodies. He that loveth his wife loveth himself.","ref":"Ephesians 5:28","synthesized":"In the same way, husbands ought to love their wives as their own bodies. He who loves his wife loves himself.","sources":{"KJV":{"text":"So ought men to love their wives as their own bodies. He that loveth his wife loveth himself."},"BSB":{"text":"In the same way, husbands ought to love their wives as their own bodies. He who loves his wife loves himself."}},"definableWords":["way","love","wife"],"peopleInVerse":[]},"29":{"text":"For no man ever yet hated his own flesh; but nourisheth and cherisheth it, even as the Lord the church:","ref":"Ephesians 5:29","synthesized":"Indeed, no one ever hated his own body, but he nourishes and cherishes it, just as Christ does the church.","sources":{"KJV":{"text":"For no man ever yet hated his own flesh; but nourisheth and cherisheth it, even as the Lord the church:"},"BSB":{"text":"Indeed, no one ever hated his own body, but he nourishes and cherishes it, just as Christ does the church."}},"definableWords":["one","Christ","church"],"peopleInVerse":[]},"30":{"text":"For we are members of his body, of his flesh, and of his bones.","ref":"Ephesians 5:30","synthesized":"For we are members of His body.","sources":{"KJV":{"text":"For we are members of his body, of his flesh, and of his bones."},"BSB":{"text":"For we are members of His body."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"For this cause shall a man leave his father and mother, and shall be joined unto his wife, and they two shall be one flesh.","ref":"Ephesians 5:31","synthesized":"“For this reason a man will leave his father and mother and be united to his wife, and the two will become one flesh.”","sources":{"KJV":{"text":"For this cause shall a man leave his father and mother, and shall be joined unto his wife, and they two shall be one flesh."},"BSB":{"text":"“For this reason a man will leave his father and mother and be united to his wife, and the two will become one flesh.”"}},"definableWords":["man","father","mother","wife","one","flesh"],"peopleInVerse":[]},"32":{"text":"This is a great mystery: but I speak concerning Christ and the church.","ref":"Ephesians 5:32","synthesized":"This mystery is profound, but I am speaking about Christ and the church.","sources":{"KJV":{"text":"This is a great mystery: but I speak concerning Christ and the church."},"BSB":{"text":"This mystery is profound, but I am speaking about Christ and the church."}},"definableWords":["Christ","church"],"peopleInVerse":[]},"33":{"text":"Nevertheless let every one of you in particular so love his wife even as himself; and the wife see that she reverence her husband.","ref":"Ephesians 5:33","synthesized":"Nevertheless, each one of you also must love his wife as he loves himself, and the wife must respect her husband.","sources":{"KJV":{"text":"Nevertheless let every one of you in particular so love his wife even as himself; and the wife see that she reverence her husband."},"BSB":{"text":"Nevertheless, each one of you also must love his wife as he loves himself, and the wife must respect her husband."}},"definableWords":["one","love","wife","husband"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"THE ARMOR OF GOD","verses":{"1":{"text":"Children, obey your parents in the Lord: for this is right.","ref":"Ephesians 6:1","synthesized":"Children, obey your parents in the Lord, for this is right.","sources":{"KJV":{"text":"Children, obey your parents in the Lord: for this is right."},"BSB":{"text":"Children, obey your parents in the Lord, for this is right."}},"definableWords":["Lord"],"peopleInVerse":[],"kingdomLens":"Paul wrote this while chained to a Roman soldier. He saw the equipment up close — belt, breastplate, shoes, shield, helmet, sword. He reimagined each piece spiritually: truth, righteousness, gospel of peace, faith, salvation, word of God. The battle is not with flesh and blood (6:12) but with principalities and powers in heavenly places.","cultural":{"title":"The armor of God","detail":"The Roman 'scutum' (shield) was nearly body-sized and curved. Soldiers locked them together to form a 'testudo' (tortoise) — overlapping shields. The shield of faith in this passage is plural in application — locked together with other believers' faith.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"Honour thy father and mother; which is the first commandment with promise;","ref":"Ephesians 6:2","synthesized":"“Honor your father and mother” (which is the first commandment with a promise),","sources":{"KJV":{"text":"Honour thy father and mother; which is the first commandment with promise;"},"BSB":{"text":"“Honor your father and mother” (which is the first commandment with a promise),"}},"definableWords":["father","mother","commandment","promise"],"peopleInVerse":[]},"3":{"text":"That it may be well with thee, and thou mayest live long on the earth.","ref":"Ephesians 6:3","synthesized":"“that it may go well with you and that you may have a long life on the earth.”","sources":{"KJV":{"text":"That it may be well with thee, and thou mayest live long on the earth."},"BSB":{"text":"“that it may go well with you and that you may have a long life on the earth.”"}},"definableWords":["life","earth"],"peopleInVerse":[]},"4":{"text":"And, ye fathers, provoke not your children to wrath: but bring them up in the nurture and admonition of the Lord.","ref":"Ephesians 6:4","synthesized":"Fathers, do not provoke your children to wrath; instead, bring them up in the discipline and instruction of the Lord.","sources":{"KJV":{"text":"And, ye fathers, provoke not your children to wrath: but bring them up in the nurture and admonition of the Lord."},"BSB":{"text":"Fathers, do not provoke your children to wrath; instead, bring them up in the discipline and instruction of the Lord."}},"definableWords":["fathers","wrath","Lord"],"peopleInVerse":[]},"5":{"text":"Servants, be obedient to them that are your masters according to the flesh, with fear and trembling, in singleness of your heart, as unto Christ;","ref":"Ephesians 6:5","synthesized":"Slaves, obey your earthly masters with respect and fear and sincerity of heart, just as you would obey Christ.","sources":{"KJV":{"text":"Servants, be obedient to them that are your masters according to the flesh, with fear and trembling, in singleness of your heart, as unto Christ;"},"BSB":{"text":"Slaves, obey your earthly masters with respect and fear and sincerity of heart, just as you would obey Christ."}},"definableWords":["fear","heart","Christ"],"peopleInVerse":[]},"6":{"text":"Not with eyeservice, as menpleasers; but as the servants of Christ, doing the will of God from the heart;","ref":"Ephesians 6:6","synthesized":"And do this not only to please them while they are watching, but as servants of Christ, doing the will of God from your heart.","sources":{"KJV":{"text":"Not with eyeservice, as menpleasers; but as the servants of Christ, doing the will of God from the heart;"},"BSB":{"text":"And do this not only to please them while they are watching, but as servants of Christ, doing the will of God from your heart."}},"definableWords":["servants","Christ","God","heart"],"peopleInVerse":[]},"7":{"text":"With good will doing service, as to the Lord, and not to men:","ref":"Ephesians 6:7","synthesized":"Serve with good will, as to the Lord and not to men,","sources":{"KJV":{"text":"With good will doing service, as to the Lord, and not to men:"},"BSB":{"text":"Serve with good will, as to the Lord and not to men,"}},"definableWords":["good","Lord","men"],"peopleInVerse":[]},"8":{"text":"Knowing that whatsoever good thing any man doeth, the same shall he receive of the Lord, whether he be bond or free.","ref":"Ephesians 6:8","synthesized":"because you know that the Lord will reward each one for whatever good he does, whether he is slave or free.","sources":{"KJV":{"text":"Knowing that whatsoever good thing any man doeth, the same shall he receive of the Lord, whether he be bond or free."},"BSB":{"text":"because you know that the Lord will reward each one for whatever good he does, whether he is slave or free."}},"definableWords":["Lord","one","good","or"],"peopleInVerse":[]},"9":{"text":"And, ye masters, do the same things unto them, forbearing threatening: knowing that your Master also is in heaven; neither is there respect of persons with him.","ref":"Ephesians 6:9","synthesized":"And masters, do the same for your slaves. Give up your use of threats, because you know that He who is both their Master and yours is in heaven, and there is no favoritism with Him.","sources":{"KJV":{"text":"And, ye masters, do the same things unto them, forbearing threatening: knowing that your Master also is in heaven; neither is there respect of persons with him."},"BSB":{"text":"And masters, do the same for your slaves. Give up your use of threats, because you know that He who is both their Master and yours is in heaven, and there is no favoritism with Him."}},"definableWords":["heaven"],"peopleInVerse":[]},"10":{"text":"Finally, my brethren, be strong in the Lord, and in the power of his might.","ref":"Ephesians 6:10","synthesized":"Finally, be strong in the Lord and in His mighty power.","sources":{"KJV":{"text":"Finally, my brethren, be strong in the Lord, and in the power of his might."},"BSB":{"text":"Finally, be strong in the Lord and in His mighty power."}},"definableWords":["strong","Lord","mighty"],"peopleInVerse":[]},"11":{"text":"Put on the whole armour of God, that ye may be able to stand against the wiles of the devil.","ref":"Ephesians 6:11","synthesized":"Put on the full armor of God, so that you can make your stand against the devil’s schemes.","sources":{"KJV":{"text":"Put on the whole armour of God, that ye may be able to stand against the wiles of the devil."},"BSB":{"text":"Put on the full armor of God, so that you can make your stand against the devil’s schemes."}},"definableWords":["God","make","stand","devil"],"peopleInVerse":[]},"12":{"text":"For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places.","ref":"Ephesians 6:12","synthesized":"For our struggle is not against flesh and blood, but against the rulers, against the authorities, against the powers of this world’s darkness, and against the spiritual forces of evil in the heavenly realms.","sources":{"KJV":{"text":"For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places."},"BSB":{"text":"For our struggle is not against flesh and blood, but against the rulers, against the authorities, against the powers of this world’s darkness, and against the spiritual forces of evil in the heavenly realms."}},"definableWords":["flesh","blood","darkness","evil"],"peopleInVerse":[]},"13":{"text":"Wherefore take unto you the whole armour of God, that ye may be able to withstand in the evil day, and having done all, to stand.","ref":"Ephesians 6:13","synthesized":"Therefore take up the full armor of God, so that when the day of evil comes, you will be able to stand your ground, and having done everything, to stand.","sources":{"KJV":{"text":"Wherefore take unto you the whole armour of God, that ye may be able to withstand in the evil day, and having done all, to stand."},"BSB":{"text":"Therefore take up the full armor of God, so that when the day of evil comes, you will be able to stand your ground, and having done everything, to stand."}},"definableWords":["God","day","evil","stand","ground"],"peopleInVerse":[]},"14":{"text":"Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness;","ref":"Ephesians 6:14","synthesized":"Stand firm then, with the belt of truth buckled around your waist, with the breastplate of righteousness arrayed,","sources":{"KJV":{"text":"Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness;"},"BSB":{"text":"Stand firm then, with the belt of truth buckled around your waist, with the breastplate of righteousness arrayed,"}},"definableWords":["stand","truth","righteousness"],"peopleInVerse":[]},"15":{"text":"And your feet shod with the preparation of the gospel of peace;","ref":"Ephesians 6:15","synthesized":"and with your feet fitted with the readiness of the gospel of peace.","sources":{"KJV":{"text":"And your feet shod with the preparation of the gospel of peace;"},"BSB":{"text":"and with your feet fitted with the readiness of the gospel of peace."}},"definableWords":["gospel","peace"],"peopleInVerse":[]},"16":{"text":"Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked.","ref":"Ephesians 6:16","synthesized":"In addition to all this, take up the shield of faith, with which you can extinguish all the flaming arrows of the evil one.","sources":{"KJV":{"text":"Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked."},"BSB":{"text":"In addition to all this, take up the shield of faith, with which you can extinguish all the flaming arrows of the evil one."}},"definableWords":["faith","evil","one"],"peopleInVerse":[]},"17":{"text":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God:","ref":"Ephesians 6:17","synthesized":"And take the helmet of salvation and the sword of the Spirit, which is the word of God.","sources":{"KJV":{"text":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God:"},"BSB":{"text":"And take the helmet of salvation and the sword of the Spirit, which is the word of God."}},"definableWords":["salvation","Spirit","word","God"],"peopleInVerse":[]},"18":{"text":"Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all saints;","ref":"Ephesians 6:18","synthesized":"Pray in the Spirit at all times, with every kind of prayer and petition. To this end, stay alert with all perseverance in your prayers for all the saints.","sources":{"KJV":{"text":"Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all saints;"},"BSB":{"text":"Pray in the Spirit at all times, with every kind of prayer and petition. To this end, stay alert with all perseverance in your prayers for all the saints."}},"definableWords":["Spirit","prayer"],"peopleInVerse":[]},"19":{"text":"And for me, that utterance may be given unto me, that I may open my mouth boldly, to make known the mystery of the gospel,","ref":"Ephesians 6:19","synthesized":"Pray also for me, that whenever I open my mouth, words may be given me so that I will boldly make known the mystery of the gospel,","sources":{"KJV":{"text":"And for me, that utterance may be given unto me, that I may open my mouth boldly, to make known the mystery of the gospel,"},"BSB":{"text":"Pray also for me, that whenever I open my mouth, words may be given me so that I will boldly make known the mystery of the gospel,"}},"definableWords":["make","gospel"],"peopleInVerse":[]},"20":{"text":"For which I am an ambassador in bonds: that therein I may speak boldly, as I ought to speak.","ref":"Ephesians 6:20","synthesized":"for which I am an ambassador in chains. Pray that I may proclaim it fearlessly, as I should.","sources":{"KJV":{"text":"For which I am an ambassador in bonds: that therein I may speak boldly, as I ought to speak."},"BSB":{"text":"for which I am an ambassador in chains. Pray that I may proclaim it fearlessly, as I should."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"But that ye also may know my affairs, and how I do, Tychicus, a beloved brother and faithful minister in the Lord, shall make known to you all things:","ref":"Ephesians 6:21","synthesized":"Tychicus, the beloved brother and faithful servant in the Lord, will tell you everything, so that you also may know about me and what I am doing.","sources":{"KJV":{"text":"But that ye also may know my affairs, and how I do, Tychicus, a beloved brother and faithful minister in the Lord, shall make known to you all things:"},"BSB":{"text":"Tychicus, the beloved brother and faithful servant in the Lord, will tell you everything, so that you also may know about me and what I am doing."}},"definableWords":["brother","servant","Lord"],"peopleInVerse":[]},"22":{"text":"Whom I have sent unto you for the same purpose, that ye might know our affairs, and that he might comfort your hearts.","ref":"Ephesians 6:22","synthesized":"I have sent him to you for this very purpose, that you may know about us, and that he may encourage your hearts.","sources":{"KJV":{"text":"Whom I have sent unto you for the same purpose, that ye might know our affairs, and that he might comfort your hearts."},"BSB":{"text":"I have sent him to you for this very purpose, that you may know about us, and that he may encourage your hearts."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Peace be to the brethren, and love with faith, from God the Father and the Lord Jesus Christ.","ref":"Ephesians 6:23","synthesized":"Peace to the brothers and love with faith from God the Father and the Lord Jesus Christ.","sources":{"KJV":{"text":"Peace be to the brethren, and love with faith, from God the Father and the Lord Jesus Christ."},"BSB":{"text":"Peace to the brothers and love with faith from God the Father and the Lord Jesus Christ."}},"definableWords":["peace","love","faith","God","Father","Lord","Christ"],"peopleInVerse":["Jesus"]},"24":{"text":"Grace be with all them that love our Lord Jesus Christ in sincerity. Amen.","ref":"Ephesians 6:24","synthesized":"Grace to all who love our Lord Jesus Christ with an undying love.","sources":{"KJV":{"text":"Grace be with all them that love our Lord Jesus Christ in sincerity. Amen."},"BSB":{"text":"Grace to all who love our Lord Jesus Christ with an undying love."}},"definableWords":["grace","love","Lord","Christ"],"peopleInVerse":["Jesus"]}}}};